        # Check process CTA
        if "process" in lp and lp["process"].get("ctaHref", "") == "#":
            found.append(f"{lp_key}.process.ctaHref")

        # Check final CTA
        if "cta" in lp and lp["cta"].get("buttonHref", "") == "#":
            found.append(f"{lp_key}.cta.buttonHref")

        # Check program tiers
        if "programs" in lp:
            for i, tier in enumerate(lp["programs"].get("tiers", [])):
                if tier.get("ctaHref", "") == "#":
                    found.append(f"{lp_key}.programs.tiers[{i}].ctaHref")
                elif "calendly" in tier.get("ctaHref", "") and "utm_" not in tier["ctaHref"]:
